import{_ as d,o as a,c as r,a4 as e}from"./chunks/framework.E9a65_Io.js";const c=JSON.parse('{"title":"子领域一","description":"","frontmatter":{},"headers":[],"relativePath":"subrealm-one.md","filePath":"subrealm-one.md"}'),s={name:"subrealm-one.md"};function n(h,t,o,l,m,i){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="子领域一" tabindex="-1">子领域一 <a class="header-anchor" href="#子领域一" aria-label="Permalink to &quot;子领域一&quot;">​</a></h1><p>这是笨猫探穴的第一个子领域，通常是你进入的第二个或第三个世界。这个世界有 7 个普通地层，全部基于世界各大洲命名（南极洲除外）。这个世界只有一把镐子——生命之树，它有 5 次升级可以强化。这里有 7 个普通齿轮，都提供小幅增益。这个世界只允许使用镐子生命之树和虫洞灭绝者（仅限合成未知之球后）。</p><p>建议在获得无限收集器后再来这里，这里只需获取前两个齿轮。之后就可以暂时不管这个世界，直到你完成<a href="./world-one.html">世界一</a>和<a href="./world-two.html">世界二</a>。因为要获得这里的奖杯，需要将生命之树升到最高级，并找到稀有度为 1/12.5T 的矿石 🏁。</p><h3 id="地层顺序" tabindex="-1">地层顺序 <a class="header-anchor" href="#地层顺序" aria-label="Permalink to &quot;地层顺序&quot;">​</a></h3><table tabindex="0"><thead><tr><th>地层</th><th>深度范围</th></tr></thead><tbody><tr><td>🇸🇨 非洲层</td><td>1m - 1,999m</td></tr><tr><td>🇧🇳 亚洲层</td><td>2,000m - 3,999m</td></tr><tr><td>🇰🇳 北美洲层</td><td>4,000m - 5,999m</td></tr><tr><td>🇰🇳 欧洲层</td><td>6,000m - 7,999m</td></tr><tr><td>🇸🇷 南美洲层</td><td>8,000m - 9,999m</td></tr><tr><td>🇹🇻 大洋洲层</td><td>10,000m - 11,999m</td></tr><tr><td>🇺🇳 联合国层</td><td>12,000m - ∞</td></tr></tbody></table><h3 id="齿轮" tabindex="-1">齿轮 <a class="header-anchor" href="#齿轮" aria-label="Permalink to &quot;齿轮&quot;">​</a></h3><table tabindex="0"><thead><tr><th>齿轮</th><th>效果</th></tr></thead><tbody><tr><td><span class="grad-text g3-replicator">复制器原型</span></td><td>10% 概率复制挖掘到的任何稀有矿石（1/750k+）</td></tr><tr><td><span class="grad-text g3-hyperdrive">超光速加速器</span></td><td>技能触发概率 +15%</td></tr><tr><td><span class="grad-text g3-automaton">超能自动机</span></td><td>自动循环并激活就绪的强化。-25% 冷却时间，+50% 激活时间</td></tr><tr><td><span class="grad-text g3-alteration">变更重复器</span></td><td>如果矿石是普通变体，额外进行一次变体判定</td></tr><tr><td><span class="grad-text g3-stratum">地层无限器</span></td><td>挖掘地层方块时有 5% 概率获得 30 倍地层方块奖励</td></tr><tr><td><span class="grad-text g3-biome">生物群系附魔师</span></td><td>洞穴类型加成 1.75 倍</td></tr><tr><td><span class="grad-text g3-reaper">天界收割者</span></td><td>允许任何无限收集器挖掘天界等级矿石</td></tr></tbody></table><h3 id="生命之树" tabindex="-1">生命之树 <a class="header-anchor" href="#生命之树" aria-label="Permalink to &quot;生命之树&quot;">​</a></h3><p><span class="grad-text g3-tree">生命之树</span> 是子领域一中唯一的镐子，有 5 次升级可供强化。获得该世界奖杯后，可在<a href="./world-one.html">世界一</a>中使用。</p><table tabindex="0"><thead><tr><th>升级</th><th>挖掘</th><th>揭示</th><th>幸运</th><th>触发率</th><th>一致性</th></tr></thead><tbody><tr><td>升级 0</td><td>4,383</td><td>4,576</td><td>1.05x</td><td>1/500</td><td>9.1</td></tr><tr><td>升级 1</td><td>19,928</td><td>20,978</td><td>3x</td><td>1/500</td><td>125.86</td></tr><tr><td>升级 2</td><td>30,397</td><td>33,246</td><td>10x</td><td>1/500</td><td>664.92</td></tr><tr><td>升级 3</td><td>37,468</td><td>41,654</td><td>20x</td><td>1/500</td><td>1,666.16</td></tr><tr><td>升级 4</td><td>46,650</td><td>54,781</td><td>40x</td><td>1/500</td><td>4,382.48 ×2</td></tr><tr><td>升级 5</td><td>54,298</td><td>63,893</td><td>100x</td><td>1/500</td><td>12,778.6 ×3</td></tr></tbody></table><hr><p><em>由 <a href="https://the-silly-caverns.fandom.com/wiki/Subrealm_One" target="_blank" rel="noreferrer">笨猫探穴 Wiki</a> 汉化</em></p>',12)])])}const b=d(s,[["render",n]]);export{c as __pageData,b as default};
